DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGchoicemacros.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "parserPopUp.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Fraction");
Context()->noreduce('(-x)+y', '(-x)-y');
$m[0] = Fraction(random_coprime([1..9],[2..9]));
do {
  $m[1] = Fraction(random_coprime([1..9],[2..9]));
} until ($m[1] != $m[0]);
($h[0], $k[0], $b[1]) = (-9..9)[NchooseK(19,3)];
$f[0] = Formula("$m[0](x-$h[0])+$k[0]")->reduce;
$f[1] = Formula("$m[1] x + $b[1]")->reduce;
$dropdown = DropDown(["Zero", "One", "Two", "More than two but finitely many", "Infinitely many"], 1, showInStatic => 0);
$dropdown2 = DropDown(["Dependent", "Inconsistent", "None of the above"], 2, showInStatic => 0);

############################################################
# Body
############################################################

BEGIN_PGML
Simply by looking closely at the linear equations, determine how many solutions the system will have. And state whether the system is dependent, inconsistent, or neither.

[`\newcommand{\amp}{&}
                  \left\{
                    \begin{alignedat}{3}
                      y \amp= [$f[0]]\\
                      y \amp= [$f[1]]
                    \end{alignedat}
                  \right.
                `]

[_]{$dropdown}{5}

[_]{$dropdown2}{5}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
